type UserStore struct {
	mu    sync.RWMutex
	users map[string]*User
	counter int
}

func NewUserStore() *UserStore {
	return &UserStore{
		users: make(map[string]*User),
	}
}

func (s *UserStore) Create(email, name string) *User {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.counter++
	user := &User{
		Id:        fmt.Sprintf("user-%d", s.counter),
		Email:     email,
		Name:      name,
		CreatedAt: timestamppb.Now(),
		Active:    true,
	}
	s.users[user.Id] = user
	return user
}

func (s *UserStore) Get(id string) (*User, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	return u, ok
}

func (s *UserStore) Update(id, email, name string) (*User, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[id]
	if !ok {
		return nil, false
	}
	if email != "" {
		u.Email = email
	}
	if name != "" {
		u.Name = name
	}
	return u, true
}

func (s *UserStore) Delete(id string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	_, ok := s.users[id]
	if ok {
		delete(s.users, id)
	}
	return ok
}

func (s *UserStore) List(pageSize int32) []*User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if pageSize <= 0 {
		pageSize = 10
	}
	users := make([]*User, 0, len(s.users))
	for _, u := range s.users {
		users = append(users, u)
		if int32(len(users)) >= pageSize {
			break
		}
	}
	return users
}

type OrderStore struct {
	mu      sync.RWMutex
	orders  map[string]*Order
	counter int
}

func NewOrderStore() *OrderStore {
	return &OrderStore{
		orders: make(map[string]*Order),
	}
}

func (s *OrderStore) Create(userId string, items []*OrderItem) *Order {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.counter++
	var total float64
	for _, item := range items {
		total += item.Price * float64(item.Quantity)
	}
	order := &Order{
		Id:          fmt.Sprintf("order-%d", s.counter),
		UserId:      userId,
		Items:       items,
		TotalAmount: total,
		Status:      OrderStatus_PENDING,
		CreatedAt:   timestamppb.Now(),
	}
	s.orders[order.Id] = order
	return order
}

func (s *OrderStore) Get(id string) (*Order, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	o, ok := s.orders[id]
	return o, ok
}

func (s *OrderStore) ListByUser(userId string, pageSize int32) []*Order {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if pageSize <= 0 {
		pageSize = 10
	}
	orders := make([]*Order, 0)
	for _, o := range s.orders {
		if userId == "" || o.UserId == userId {
			orders = append(orders, o)
			if int32(len(orders)) >= pageSize {
				break
			}
		}
	}
	return orders
}

func (s *OrderStore) Cancel(id, reason string) (*Order, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	o, ok := s.orders[id]
	if !ok {
		return nil, false
	}
	if o.Status == OrderStatus_DELIVERED || o.Status == OrderStatus_CANCELLED {
		return nil, false
	}
	o.Status = OrderStatus_CANCELLED
	return o, true
}

type PaymentStore struct {
	mu       sync.RWMutex
	payments map[string]*Payment
	counter  int
}

func NewPaymentStore() *PaymentStore {
	return &PaymentStore{
		payments: make(map[string]*Payment),
	}
}

func (s *PaymentStore) Process(orderID, userID string, amount float64, currency string, method PaymentMethod) *Payment {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.counter++
	payment := &Payment{
		Id:            fmt.Sprintf("pay-%d", s.counter),
		OrderId:       orderID,
		UserId:        userID,
		Amount:        amount,
		Currency:      currency,
		Method:        method,
		Status:        PaymentStatus_PAYMENT_COMPLETED,
		TransactionId: fmt.Sprintf("txn-%d-%d", s.counter, time.Now().UnixNano()),
		CreatedAt:     timestamppb.Now(),
	}
	s.payments[payment.Id] = payment
	return payment
}

func (s *PaymentStore) Get(id string) (*Payment, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	p, ok := s.payments[id]
	return p, ok
}

func (s *PaymentStore) Refund(paymentID string, amount float64) (*RefundResponse, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	p, ok := s.payments[paymentID]
	if !ok {
		return nil, false
	}
	if p.Status != PaymentStatus_PAYMENT_COMPLETED {
		return nil, false
	}
	if amount <= 0 || amount > p.Amount {
		amount = p.Amount
	}
	p.Status = PaymentStatus_PAYMENT_REFUNDED
	s.counter++
	return &RefundResponse{
		RefundId:  fmt.Sprintf("refund-%d", s.counter),
		PaymentId: paymentID,
		Amount:    amount,
		Status:    PaymentStatus_PAYMENT_REFUNDED,
	}, true
}

func (s *PaymentStore) List(userID, orderID string, pageSize int32) []*Payment {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if pageSize <= 0 {
		pageSize = 10
	}
	payments := make([]*Payment, 0)
	for _, p := range s.payments {
		if (userID == "" || p.UserId == userID) && (orderID == "" || p.OrderId == orderID) {
			payments = append(payments, p)
			if int32(len(payments)) >= pageSize {
				break
			}
		}
	}
	return payments
}

