func (s *UserManagementService) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	log.Printf("[UserService] CreateUser: email=%s, name=%s", req.Email, req.Name)
	if req.Email == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	user := s.store.Create(req.Email, req.Name)
	log.Printf("[UserService] Created user: %s", user.Id)
	return user, nil
}

func (s *UserManagementService) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	log.Printf("[UserService] GetUser: id=%s", req.Id)
	user, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	return user, nil
}

func (s *UserManagementService) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	log.Printf("[UserService] UpdateUser: id=%s", req.Id)
	user, ok := s.store.Update(req.Id, req.Email, req.Name)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	return user, nil
}

func (s *UserManagementService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*emptypb.Empty, error) {
	log.Printf("[UserService] DeleteUser: id=%s", req.Id)
	ok := s.store.Delete(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	return &emptypb.Empty{}, nil
}

func (s *UserManagementService) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	log.Printf("[UserService] ListUsers: pageSize=%d", req.PageSize)
	users := s.store.List(req.PageSize)
	return &ListUsersResponse{Users: users}, nil
}

// --- Order Service ---

type OrderService struct {
	store *OrderStore
}

func NewOrderService() *OrderService {
	return &OrderService{
		store: NewOrderStore(),
	}
}

func (s *OrderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	log.Printf("[OrderService] CreateOrder: userId=%s, items=%d", req.UserId, len(req.Items))
	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}
	order := s.store.Create(req.UserId, req.Items)
	log.Printf("[OrderService] Created order: %s, total: %.2f", order.Id, order.TotalAmount)
	return order, nil
}

func (s *OrderService) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	log.Printf("[OrderService] GetOrder: id=%s", req.Id)
	order, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}
	return order, nil
}

func (s *OrderService) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	log.Printf("[OrderService] ListOrders: userId=%s", req.UserId)
	orders := s.store.ListByUser(req.UserId, req.PageSize)
	return &ListOrdersResponse{Orders: orders}, nil
}

func (s *OrderService) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	log.Printf("[OrderService] CancelOrder: id=%s, reason=%s", req.Id, req.Reason)
	order, ok := s.store.Cancel(req.Id, req.Reason)
	if !ok {
		return nil, status.Errorf(codes.FailedPrecondition, "cannot cancel order %s", req.Id)
	}
	return order, nil
}

// --- Payment Service ---

type PaymentService struct {
	store *PaymentStore
}

func NewPaymentService() *PaymentService {
	return &PaymentService{
		store: NewPaymentStore(),
	}
}

func (s *PaymentService) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	log.Printf("[PaymentService] ProcessPayment: orderId=%s, amount=%.2f %s", req.OrderId, req.Amount, req.Currency)
	if req.OrderId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		req.Currency = "USD"
	}
	payment := s.store.Process(req.OrderId, req.UserId, req.Amount, req.Currency, req.Method)
	log.Printf("[PaymentService] Payment processed: %s, txn: %s", payment.Id, payment.TransactionId)
	return payment, nil
}

func (s *PaymentService) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	log.Printf("[PaymentService] GetPayment: id=%s", req.Id)
	payment, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}
	return payment, nil
}

func (s *PaymentService) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundResponse, error) {
	log.Printf("[PaymentService] RefundPayment: paymentId=%s, amount=%.2f", req.PaymentId, req.Amount)
	refund, ok := s.store.Refund(req.PaymentId, req.Amount)
	if !ok {
		return nil, status.Errorf(codes.FailedPrecondition, "cannot refund payment %s", req.PaymentId)
	}
	return refund, nil
}

func (s *PaymentService) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	log.Printf("[PaymentService] ListPayments: userId=%s, orderId=%s", req.UserId, req.OrderId)
	payments := s.store.List(req.UserId, req.OrderId, req.PageSize)
	return &ListPaymentsResponse{Payments: payments}, nil
}

