// ============================================================
// Logging Interceptor
// ============================================================

func loggingUnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	start := time.Now()
	log.Printf("[INTERCEPTOR] --> %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		st, _ := status.FromError(err)
		log.Printf("[INTERCEPTOR] <-- %s | %s | %v | err: %s", info.FullMethod, st.Code(), duration, st.Message())
	} else {
		log.Printf("[INTERCEPTOR] <-- %s | OK | %v", info.FullMethod, duration)
	}

	return resp, err
}

// ============================================================
// Recovery Interceptor
// ============================================================

func recoveryUnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("[RECOVERY] Panic in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

// ============================================================
// Main - Server Setup
// ============================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptors
	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			recoveryUnaryInterceptor,
			loggingUnaryInterceptor,
		),
	)

	// Register service implementations
	userService := NewUserManagementService()
	orderService := NewOrderService()
	paymentService := NewPaymentService()

	grpcServer.RegisterService(&userManagementServiceDesc, userService)
	grpcServer.RegisterService(&orderServiceDesc, orderService)
	grpcServer.RegisterService(&paymentServiceDesc, paymentService)

	// Enable gRPC reflection for development and testing
	// This allows tools like grpcurl, grpcui, and Postman to discover services
	reflection.Register(grpcServer)

	log.Println("============================================================")
	log.Println("  Microservices Development gRPC Server")
	log.Println("============================================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED (development mode)")
	log.Println("")
	log.Println("  Registered Services:")
	log.Println("    - microservices.UserManagementService")
	log.Println("      * CreateUser, GetUser, UpdateUser, DeleteUser, ListUsers")
	log.Println("    - microservices.OrderService")
	log.Println("      * CreateOrder, GetOrder, ListOrders, CancelOrder")
	log.Println("    - microservices.PaymentService")
	log.Println("      * ProcessPayment, GetPayment, RefundPayment, ListPayments")
	log.Println("")
	log.Println("  Test with grpcurl:")
	log.Println("    grpcurl -plaintext localhost:50051 list")
	log.Println("    grpcurl -plaintext localhost:50051 describe")
	log.Println("    grpcurl -plaintext -d '{\"email\":\"test@example.com\",\"name\":\"Test User\"}' localhost:50051 microservices.UserManagementService/CreateUser")
	log.Println("============================================================")

	// Seed some test data
	seedTestData(userService, orderService, paymentService)

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

func seedTestData(userSvc *UserManagementService, orderSvc *OrderService, paymentSvc *PaymentService) {
	log.Println("[SEED] Creating test data...")

	// Create test users
	user1, _ := userSvc.CreateUser(context.Background(), &CreateUserRequest{
		Email: "alice@example.com",
		Name:  "Alice Johnson",
	})
	user2, _ := userSvc.CreateUser(context.Background(), &CreateUserRequest{
		Email: "bob@example.com",
		Name:  "Bob Smith",
	})

	// Create test orders
	order1, _ := orderSvc.CreateOrder(context.Background(), &CreateOrderRequest{
		UserId: user1.Id,
		Items: []*OrderItem{
			{ProductId: "prod-1", Quantity: 2, Price: 29.99},
			{ProductId: "prod-2", Quantity: 1, Price: 49.99},
		},
	})
	orderSvc.CreateOrder(context.Background(), &CreateOrderRequest{
		UserId: user2.Id,
		Items: []*OrderItem{
			{ProductId: "prod-3", Quantity: 3, Price: 9.99},
		},
	})

	// Create test payments
	paymentSvc.ProcessPayment(context.Background(), &ProcessPaymentRequest{
		OrderId:  order1.Id,
		UserId:   user1.Id,
		Amount:   order1.TotalAmount,
		Currency: "USD",
		Method:   PaymentMethod_CREDIT_CARD,
	})

	log.Println("[SEED] Test data created successfully")
	log.Printf("[SEED]   Users: %s (%s), %s (%s)", user1.Name, user1.Id, user2.Name, user2.Id)
}